INSERT INTO `updates` VALUES (1,'0.2','Resource Management Update','Major update bringing resource management, terrain parks, and quality-of-life improvements to Ski Manager.','major','2026-06-01','2026-06-03 14:37:52'),(2,'0.1','Complete Rebuild','Ski Manager has been completely rebuilt from the ground up with a modern technology stack and dramatically expanded gameplay.','major','2026-05-27','2026-06-03 14:37:52'),(3,'0.3','Polish & Compliance Update','Cookie consent, legal pages, analytics setup, cross-system integration, and quality-of-life improvements.','minor','2026-06-03','2026-06-03 14:39:16'),(4,'0.4','Bug Fixes & Dashboard Improvements','Bug fixes, dashboard improvements, and developer tooling.','minor','2026-06-04','2026-06-04 21:02:31'),(6,'0.5','Season 1: Park City','Season 1 officially launches June 6, 2026 at 12:00 AM Eastern Time. All players start fresh on Park City Mountain Resort. Sector 1 is open with lifts and slopes ready to build.','major','2026-06-06','2026-06-06 02:27:28');
/*!40000 ALTER TABLE `updates` ENABLE KEYS */;
