INSERT INTO `update_items` VALUES (1,1,'New Features','new','Energy Management - Build power grid connections, solar panels, wind turbines, and diesel generators to power your resort.',1),(2,1,'New Features','new','Water Management - Construct reservoirs, wells, river pumps, and water recycling plants to supply snowmaking.',2),(3,1,'New Features','new','Terrain Parks - Build halfpipes, jump lines, rail gardens, and slopestyle courses with dedicated park crew.',3),(4,1,'New Features','new','Parking & Transit - Build surface lots, parking garages, shuttle stops, and a village gondola with dynamic pricing.',4),(5,1,'New Features','new','VIP Guests - Random celebrity visitors, film crews, influencers, and ski teams arrive based on resort quality.',5),(6,1,'New Features','new','Resort Analysis - Detailed report analyzing your resort across seven categories for 20 Genepis.',6),(7,1,'New Features','new','Notification System - Bell icon with real-time notifications for construction, breakdowns, VIP arrivals.',7),(8,1,'New Features','new','Tutorial System - Guided tutorial for new players covering hiring, building, and resort setup.',8),(9,1,'New Features','new','Google Sign-In - Sign up or log in with your Google account.',9),(10,1,'Dashboard Improvements','improved','iOS-style widget system with small, medium, and large sizes',10),(11,1,'Dashboard Improvements','improved','Drag-and-drop widget reordering',11),(12,1,'Dashboard Improvements','improved','Show/hide widgets with edit mode',12),(13,1,'Dashboard Improvements','improved','New widgets: Parking, Terrain Parks, Finances, Staff, Equipment, Insurance, Loans, Marketing',13),(14,1,'Dashboard Improvements','improved','All stats now pull real data from the database',14),(15,1,'Dashboard Improvements','improved','Resort star rating displayed in the stats bar',15),(16,1,'Quality of Life','improved','Equipment durability system - equipment degrades with use and needs repair',16),(17,1,'Quality of Life','improved','Resort open/close toggle - close your resort for maintenance days',17),(18,1,'Quality of Life','improved','Expanded settings page with resort naming, tutorial restart, and data management',18),(19,1,'Quality of Life','improved','Improved mobile navigation with categorized hamburger menu',19),(20,1,'Quality of Life','improved','Faster Font Awesome icon loading',20),(21,1,'Quality of Life','improved','Admin panel improvements: economy overview, activity log viewer, manual game tick',21),(22,2,'Core Systems','new','Modern UI built with Tailwind CSS and DaisyUI with light/dark theme support',1),(23,2,'Core Systems','new','Interactive trail map powered by Leaflet.js with map data from Mapsynergy',2),(24,2,'Core Systems','new','Comprehensive staff management with 10 different roles',3),(25,2,'Core Systems','new','Dynamic weather system that affects visitor count and snow conditions',4),(26,2,'Core Systems','new','Full financial system with income tracking, expenses, loans, and insurance',5),(27,2,'Core Systems','new','8 categories of buildings including hotels, restaurants, and retail shops',6),(28,2,'Core Systems','new','Snowmaking and night skiing operations',7),(29,2,'Core Systems','new','Government regulations and environmental compliance',8),(30,2,'Core Systems','new','Equipment shop with real-world brands (PistenBully, Prinoth, TechnoAlpin)',9),(31,2,'Core Systems','new','Achievement system with 12 trackable goals',10),(32,2,'Core Systems','new','Daily bonus with streak rewards',11),(33,2,'Core Systems','new','Leaderboard and tournament system',12),(34,2,'Core Systems','new','Genepis premium currency',13),(35,2,'Core Systems','new','Automated game engine with daily processing via cron',14),(36,2,'Core Systems','new','Admin panel for game management',15),(37,2,'Core Systems','new','WCAG 2.2 accessibility compliance',16),(38,2,'Core Systems','new','Mobile responsive design',17),(39,3,'New Features','new','Cookie consent banner with three options: Accept All, Analytics Only, Reject All',1),(40,3,'New Features','new','Google Consent Mode v2 integration for analytics and advertising signals',2),(41,3,'New Features','new','Cookie preferences accessible from Settings page',3),(42,3,'New Features','new','Updates page now database-driven for easier changelog management',4),(43,3,'Improvements','improved','Rewritten Privacy Policy with GDPR and CCPA coverage',5),(44,3,'Improvements','improved','Rewritten Terms of Service with expanded user conduct and virtual currency sections',6),(45,3,'Improvements','improved','Rewritten Cookie Policy with detailed cookie tables and Consent Mode explanation',7),(46,3,'Improvements','improved','Rewritten Disclaimer with weather data and simulation accuracy sections',8),(47,3,'Improvements','improved','Cross-system integration links between snowmaking, grooming, equipment, and energy pages',9),(48,3,'Improvements','improved','Resource status bars (energy/water supply vs demand) on snowmaking page',10),(49,3,'Fixes','fixed','Fixed snowmaking page crash caused by undefined $db variable',11),(50,3,'Fixes','fixed','Fixed altitude() type error when passed string instead of int',12),(51,3,'Fixes','fixed','Google Analytics and Search Console now fully operational',13),(52,3,'Fixes','fixed','Internal traffic filter configured to exclude developer visits from analytics',14),(53,3,'Other','improved','Removed beta acceptance flow from v1 site',15),(54,3,'Other','improved','Updated all legal pages to use correct contact email and domain',16),(55,4,'Fixes','fixed','Critical server errors preventing site access',1),(56,4,'Fixes','fixed','Weather display showing incorrect day data on homepage and dashboard',2),(57,4,'Fixes','fixed','Marketing page crash from missing unlock_check helper',3),(58,4,'Fixes','fixed','Game tick crash from resort rating array multiplication',4),(59,4,'Fixes','fixed','Achievements page crash for logged-out users',5),(60,4,'Fixes','fixed','Route deprecation warnings for uppercase HTTP methods',6),(61,4,'Fixes','fixed','Admin tick trigger timeout via background execution',7),(62,4,'Improvements','improved','Dashboard stats widget now shows visitor count and net profit',8),(63,4,'Improvements','improved','Weather widget displays 5-day forecast with snowfall indicators',9),(64,4,'Improvements','improved','Achievement alerts widget shows closest-to-completion when all claimed',10),(65,4,'Improvements','improved','Finances widget shows color-coded net profit',11),(66,4,'Other','new','PHPStan static code analysis for catching type errors',12),(67,4,'Other','new','Database migrations for updates table',13),(68,6,'Season 1','new','Season 1: Park City Mountain Resort - 135 days of skiing starting June 6 at 12:00 AM ET',1),(69,6,'Season 1','new','Sector 1 open with lifts and slopes ready to build',2),(70,6,'Season 1','new','All players start on the same resort map for fair competition',3),(71,6,'Season 1','new','Seasonal leaderboard tracks progress across all players',4),(72,6,'Gameplay','new','Snow quality system - slopes track powder, groomed, packed, icy, and bare conditions',5),(73,6,'Gameplay','new','Resort tours - visit other players resorts and like them',6),(74,6,'Gameplay','new','Sector system - new areas unlock as the season progresses',7),(75,6,'Gameplay','improved','Trail map rebuilt with admin drawing tools, midstations, and segment connections',8),(76,6,'Gameplay','improved','Dashboard shows visitor count, net profit, and 5-day weather forecast',9),(77,6,'Gameplay','improved','Realistic weather temperature ranges',10);
